import scala.collection.mutable

def solve(n: Long, edges: Array[Array[Long]]): Long = {
    val adj = mutable.HashMap[Long, List[(Long, (Long, Long))]]()
    for (edge <- edges) {
        val u = edge(0)
        val v = edge(1)
        val start = edge(2)
        val end = edge(3)
        adj.getOrElseUpdate(u, List.empty).append((v, (start, end)))
    }

    val dist = mutable.HashMap[Long, Long]()
    for (i <- 0 until n) dist(i) = Long.MaxValue
    dist(0) = 0

    import scala.collection.mutable.PriorityQueue
    val pq = PriorityQueue[(Long, Long)]()(Ordering.by(_._1))
    pq.enqueue((0, 0))

    while (pq.nonEmpty) {
        val (time, node) = pq.dequeue()
        if (node == n - 1) return time
        if (time > dist(node)) continue

        // Try to stay at the current node
        val newTime = time + 1
        if (newTime < dist(node)) {
            dist(node) = newTime
            pq.enqueue((newTime, node))
        }

        // Try to take each outgoing edge
        for ((v, (start, end)) <- adj.getOrElse(node, List.empty)) {
            if (start <= time && time <= end) {
                val newTime = time + 1
                if (newTime < dist.getOrElse(v, Long.MaxValue)) {
                    dist(v) = newTime
                    pq.enqueue((newTime, v))
                }
            }
        }
    }

    -1
}
